// ─────────────────────────────────────────────────────────────────────────
// NODE: "Normalize input"  (CONVERSATIONAL REWRITE 2026-07-08)
// The AI now WRITES the reply (warm Rahul, English only) AND extracts the 4
// details. Parse+validate is the deterministic safety net (backstop, dedup,
// code-driven Yes/No step, returning-visitor logic, sheet/CRM mapping).
// Banked profile (WhatsApp + past destinations) is persisted in workflow static
// data keyed by ig_user_id so a returning visitor is greeted back and never
// re-asked for their number.
// ⚠️ Code node MUST return [{ json: { ... } }].
// ─────────────────────────────────────────────────────────────────────────

const wh = $('Webhook').first().json.body || {};
const s = (v) => (v === undefined || v === null ? '' : String(v).trim());
const OB = String.fromCharCode(123) + String.fromCharCode(123);
const CB = String.fromCharCode(125) + String.fromCharCode(125);
const clean = (v) => { const t = s(v); return (t.slice(0, 2) === OB && t.slice(-2) === CB) ? '' : t; };
const pick = (a, b) => { const x = clean(a); return x !== '' ? x : clean(b); };

// -- DEDUP LAYER 1: synchronous same-message guard. --
const _sd = $getWorkflowStaticData('global');
_sd.seenMsg = _sd.seenMsg || {};
const _now = Date.now();
for (const _k in _sd.seenMsg) { if (_now - _sd.seenMsg[_k] > 3600000) delete _sd.seenMsg[_k]; }
const _dupKey = s(wh.ig_user_id) + '|' + s(wh.message_text);
if (s(wh.ig_user_id) && s(wh.message_text) && _sd.seenMsg[_dupKey] && (_now - _sd.seenMsg[_dupKey] < 4000)) return [];
if (_dupKey) _sd.seenMsg[_dupKey] = _now;
const _msgId = 'L' + _now + '-' + Math.floor(Math.random() * 1000000);

// -- sheet row (Lookup existing lead) --
let row = {};
try {
  const inItems = $input.all();
  if (inItems && inItems.length && inItems[0] && inItems[0].json) {
    const j = inItems[0].json;
    if (j && (clean(j.destination) || clean(j.normalized_destination) || clean(j.travel_date) || clean(j.pax) || clean(j.whatsapp_number) || clean(j.quick_assistance) || clean(j['notes - AI']) || clean(j.first_contact_ts) || clean(j.name))) row = j;
  }
} catch (e) { row = {}; }

const userMsg = s(wh.message_text);

// -- BANKED PROFILE (persists across the 48h reset; static data) --
_sd.profiles = _sd.profiles || {};
const uid = s(wh.ig_user_id);
// prune profiles older than 365 days
for (const _p in _sd.profiles) { if (_now - ((_sd.profiles[_p] || {}).ts || 0) > 365 * 24 * 3600 * 1000) delete _sd.profiles[_p]; }
const profile = _sd.profiles[uid] || { whatsapp: '', past: [] };
const bankedWhatsapp = clean(profile.whatsapp) || pick(row.whatsapp_number, '');

const known = {
  destination:            pick(row.destination, wh.destination),
  normalized_destination: pick(row.normalized_destination, wh.normalized_destination),
  travel_date:            pick(row.travel_date, wh.travel_date),
  pax:                    pick(row.pax, wh.pax),
  whatsapp_number:        pick(row.whatsapp_number, wh.whatsapp_number) || bankedWhatsapp,
  quick_assistance:       pick(row.quick_assistance, wh.quick_assistance),
};

// -- 48h / greeting reset (same rule as before) --
function parseIST(ts) {
  const m = String(ts).trim().match(/^(\d{4})-(\d{1,2})-(\d{1,2})[ T](\d{1,2}):(\d{2}):(\d{2})$/);
  if (!m) return NaN;
  const [, y, mo, d, h, mi, se] = m.map(Number);
  const pad = (n) => String(n).padStart(2, '0');
  return new Date(`${y}-${pad(mo)}-${pad(d)}T${pad(h)}:${pad(mi)}:${pad(se)}+05:30`).getTime();
}
const lastUpdateTs = clean(row.last_update_ts) || clean(row.first_contact_ts);
let hoursSince = Infinity;
if (lastUpdateTs) { const lastMs = parseIST(lastUpdateTs); if (!isNaN(lastMs)) hoursSince = (_now - lastMs) / 3600000; }
const _greetTokens = userMsg.toLowerCase().replace(/[^a-z\s]/g, ' ').trim().split(/\s+/).filter(Boolean);
const GREET_WORDS = ['hi','hii','hiii','hiiii','hello','helo','hellooo','hey','heyy','heyyy','hai','hlo','yo','gm','gn','good','morning','afternoon','evening','night','namaste','vanakkam','hola','greetings','sir','madam','mam','team','there','bro','ji','anna','dear','all'];
const isPureGreeting = _greetTokens.length > 0 && _greetTokens.length <= 4 && _greetTokens.every((t) => GREET_WORDS.indexOf(t) !== -1);
const resetConversation = (hoursSince === Infinity) || (hoursSince >= 2 && isPureGreeting);

// A previously-finished lead: completed the funnel OR has a banked number.
const wasCompleted = !!(clean(row.quick_assistance) || clean(row.status) === 'qualified' || clean(profile.whatsapp));

if (resetConversation) {
  known.destination = '';
  known.normalized_destination = '';
  known.travel_date = '';
  known.pax = '';
  known.quick_assistance = '';
  known.whatsapp_number = bankedWhatsapp; // BANK the number across visits
}

// QA in-flight overlay (Button handler may not be in the sheet yet)
_sd.qaDone = _sd.qaDone || {};
for (const _q in _sd.qaDone) { if (_now - (_sd.qaDone[_q].ts || 0) > 72 * 3600 * 1000) delete _sd.qaDone[_q]; }
const _qaHit = _sd.qaDone[uid];
if (resetConversation) { delete _sd.qaDone[uid]; if (_sd.awaitingQA) delete _sd.awaitingQA[uid]; }
else if (_qaHit && !known.quick_assistance) { known.quick_assistance = _qaHit.v; }

const hasDestination = !!(known.destination || known.normalized_destination);
const hasTravelDate = !!known.travel_date;
const hasPax = !!known.pax;
const hasPhone = !!known.whatsapp_number;
const hasQuickAssist = !!known.quick_assistance;

// -- VISITOR STATUS --
let visitorStatus;
if (resetConversation) visitorStatus = bankedWhatsapp && wasCompleted ? 'returning' : 'new';
else visitorStatus = (hasDestination || hasTravelDate || hasPax || hasQuickAssist || clean(row['notes - AI'])) ? 'continuing' : 'new';

let existingFirstContact = clean(row.first_contact_ts);
let existingNotes = pick(row['notes - AI'], wh.notes);
if (resetConversation) { existingFirstContact = ''; existingNotes = ''; }

const nowISTstr = new Date(_now + 5.5 * 3600000).toISOString().replace('T', ' ').slice(0, 19);
const convFirstContact = existingFirstContact || nowISTstr;
const _epochMs = parseIST(convFirstContact);
const _neSalt = (_sd.neSalt && _sd.neSalt[uid]) || '';
const sessionKey = uid + '|' + (isNaN(_epochMs) ? convFirstContact : _epochMs) + (_neSalt ? '|ne' + _neSalt : '');

const savedProfile = { whatsapp: bankedWhatsapp || null, past_destinations: (profile.past || []).slice(-5) };
const savedProfileJson = JSON.stringify(savedProfile);
const knownJson = JSON.stringify(known);
const notesBlock = existingNotes ? existingNotes : '(none yet)';

const igFullName = clean(wh.ig_fullname) || pick(row.name, '');
const igUsername = s(wh.ig_username);
const channel = (clean(wh.channel) || 'instagram').toLowerCase();
const channelLabel = channel === 'instagram' ? 'instagram' : 'facebook';

// -- Yes/No button detection at the quick-assistance step (code-driven QA) --
const _qaTok = userMsg.toLowerCase().replace(/[^a-z\s]/g, ' ').split(/\s+/).filter(Boolean).map((t) => t.replace(/(.)\1+/g, '$1'));
const _yesStrong = ['yes','yeah','yea','yep','yup','ya','sure'];
const _yesWeak = ['y','s','ok','okay','okey','okie','k','need','needed','want','please','pls','plz'];
const _noSet = ['no','nope','nah','na','not','dont','don','dnt'];
const _hasNoTok = _qaTok.some((t) => _noSet.indexOf(t) !== -1);
const _hasStrongYesTok = _qaTok.some((t) => _noSet.indexOf(t) === -1 && _yesStrong.indexOf(t) !== -1);
// Weak acknowledgment words (ok/k/please/...) only count as a Yes answer when they ARE
// the whole message (like a pure greeting check) - otherwise "ok thinking" or "ok wait"
// gets misread as a definitive Yes just because it contains "ok" anywhere.
const _isPureAck = _qaTok.length > 0 && _qaTok.length <= 3 && _qaTok.every((t) => _yesStrong.indexOf(t) !== -1 || _yesWeak.indexOf(t) !== -1 || _noSet.indexOf(t) !== -1);
const _hasYesTok = _hasStrongYesTok || (_isPureAck && !_hasNoTok && _qaTok.some((t) => _yesWeak.indexOf(t) !== -1));
// Required core before the QA step: returning visitors need only destination + phone.
const _coreReady = hasPhone && hasDestination && (visitorStatus === 'returning' ? true : (hasTravelDate && hasPax));
// awaitingQA is set by Parse the moment it asks the Yes/No question, so the reply is
// recognised as a button even if the sheet read hasn't caught up with the phone yet.
const _awaitQA = !!(_sd.awaitingQA && _sd.awaitingQA[uid] && (_now - _sd.awaitingQA[uid] < 72 * 3600000));
const _qaPending = (_coreReady || _awaitQA) && !hasQuickAssist;
const isButtonClick = _qaPending && (_hasNoTok || _hasYesTok);
const buttonValue = isButtonClick ? (_hasNoTok ? 'no' : 'yes') : '';

// -- POST-DONE SILENT-ACK GATE (ported from the WhatsApp bot) -- once everything is
// collected and quick assistance is answered, bare acknowledgments get no reply at
// all (and skip the AI Agent call entirely, saving tokens); real follow-up
// questions still reach the AI normally.
const postDone = _coreReady && hasQuickAssist && !isButtonClick;
const _ackWord = userMsg.toLowerCase().replace(/[^a-z]/g, '');
const POST_ACKS = ['ok', 'okay', 'okk', 'okie', 'okey', 'k', 'kk', 'hm', 'hmm', 'thanks', 'thankyou', 'thanku', 'thx', 'tq', 'great', 'nice', 'good', 'super', 'fine', 'cool', 'done', 'sure', 'welcome', 'yes', 'no'];
if (postDone && (POST_ACKS.indexOf(_ackWord) !== -1 || _ackWord === '')) { return []; }

const systemPrompt = `🔴 LANGUAGE RULE: Mirror the user's language and script EXACTLY (English→English, Tamil script→Tamil, Tanglish→Tanglish); match their emoji level. In Tamil/Tanglish ALWAYS use the respectful register — "neenga" and polite "-unga" verb forms (pannunga, sollunga, varreenga); stay warm but respectful, never rough or over-familiar ("da"/"di") unless the customer clearly does so first.

You are a friendly travel consultant for Outbound Travelers, a premium travel brand for South Indian travelers. You are chatting with someone who just commented on our Instagram or Facebook post and is interested in a trip. Your ONLY job is to warmly collect a few details and hand them to a human travel expert. You are not a general assistant.

- Your name is Rahul. When you greet for the first time, introduce yourself by name — e.g. "Hey, this is Rahul from Outbound Travelers! 👋😊". NEVER open with a generic "Welcome to Outbound Travelers" or a bare "Hey there!".
- Talk like a real, warm team member. NEVER reveal you are an AI or a bot. Never say "a real person"/"a real human" — just say "our travel expert" or "our team". Be brief, human, friendly. Light emoji is good. Never sound like a form.

VISITOR CONTEXT
Visitor status: ${visitorStatus}
Saved profile (banked from past visits): ${savedProfileJson}
NOTES SO FAR: ${notesBlock}
KNOWN DETAILS so far (already collected — NEVER ask for any of these again): ${knownJson}

THE 3 DETAILS TO COLLECT: destination, members (how many people), travel_month. (Their WhatsApp number is collected by a separate step AFTER these — do NOT ask for the number yourself; if KNOWN DETAILS already has whatsapp_number, it is on file.)

HOW TO OPEN — BASED ON VISITOR STATUS
- new: greet warmly, introduce yourself as Rahul, and ask the first missing detail (start at destination).
- continuing: do NOT re-greet; just ask the next single missing detail.
- returning: someone we've spoken to before, back via a new post. Do NOT run the full question set. (1) greet warmly as a returning friend ("welcome back!"); (2) ask which destination they want THIS time (always fresh — never assume it's the same); (3) members and month are NOT required on a return visit. Once you have the new destination, warmly acknowledge and stop (the expert hand-off happens automatically).

FULL FLOW (new/continuing), ONE question per message, in order:
1. Destination — e.g. "Hey, this is Rahul from Outbound Travelers! 👋😊 So happy you're planning a trip ✈️ May I know which destination you're planning to visit? 🌍" We specialize in Thailand, Bali, Malaysia, Singapore + select domestic, but capture ANY place warmly.
2. Members — "how many people are travelling? 👥"
3. Travel month — "which month are you planning for? 🗓️" If unsure, treat as "flexible" and move on, don't pressure.

FORMATTING: when your reply has both a short reaction/acknowledgment AND a question, put a line break between them (two short lines, like a real person texting) instead of running them together in one dense line — e.g. "Malaysia sounds amazing! 🌴\n\nHow many people are travelling with you? 👥" rather than one long sentence. Keep the words natural and warm either way.

CONVERSATION RULES: keep EVERY reply short, crisp and human — like texting a friend (1-2 short sentences max, no long paragraphs, no salesy tone). One question per message. Briefly acknowledge their answer before the next question. If they give several answers at once, capture ALL and jump to the next empty detail. Never list all questions like a form. Never re-ask something already in KNOWN DETAILS.

OFF-TOPIC / SIDE QUESTIONS: if they ask something unrelated (honeymoon packages, "is Bali safe", visa, a random question), answer/acknowledge in ONE short warm line (never invent prices/itineraries/dates — defer specifics to the WhatsApp expert), then gently bring them back and re-ask the pending next detail. Never restart the flow. Example — was just asked members and they say "btw do you do honeymoon trips?" → "Yes, honeymoons are one of our specialties 😊 our expert will plan a perfect one for you. Coming back to your trip — how many of you will be travelling? 👥".

GUARDRAILS: if asked for our phone/contact, share warmly — +91 9597959728 (call or WhatsApp) — this is the ONE exact detail you may give, then continue. Never invent or promise prices, discounts, itineraries, hotel names, availability, visa details, or fixed dates — say "our travel expert will share all those exact details on WhatsApp" and continue. Never commit beyond "an expert will contact you". SERIOUS MOMENTS: if the person is upset, has a complaint, is an existing customer with a problem, or shares something distressing → drop the sales flow, respond with genuine care, don't push, set flag "serious" or "complaint". Spam/abusive → stay polite, collect nothing, flag "spam".

OUTPUT — respond with ONLY a valid JSON object, no markdown, no backticks, no text before or after — EVERY turn with NO exceptions (even when deflecting/off-topic/chatting, the whole response is this JSON with your message inside "reply"). Schema:
{"reply":"<message to send the user, in their language>","data":{"destination":<string or null>,"members":<string or null>,"travel_month":<string or null>},"stage":"<greeting|collecting|complete>","handoff_ready":<true|false>,"flag":<null|"serious"|"complaint"|"spam">}
Set stage "complete" and handoff_ready true when destination + members + travel_month are all filled (for a returning visitor: as soon as destination is filled), or when flag is serious/complaint. Always return the full data object with all 3 keys.`;

return [{
  json: {
    ig_user_id:                uid,
    ig_username:               igUsername,
    ig_fullname:               igFullName,
    user_message:              userMsg,
    known_fields:              known,
    known_fields_json:         knownJson,
    visitor_status:            visitorStatus,
    saved_profile:             savedProfile,
    banked_whatsapp:           bankedWhatsapp,
    prior_chat:                visitorStatus === 'continuing',
    existing_first_contact_ts: existingFirstContact,
    conv_first_contact:        convFirstContact,
    session_key:               sessionKey,
    existing_notes:            existingNotes,
    system_prompt:             systemPrompt,
    msg_id:                    _msgId,
    channel:                   channel,
    channel_label:             channelLabel,
    is_button_click:           isButtonClick,
    button_value:              buttonValue,
  },
}];

// ─────────────────────────────────────────────────────────────────────────
// NODE: "Parse + validate"  (CONVERSATIONAL REWRITE 2026-07-08)
// The AI now writes the warm reply + extracts destination/members/travel_month.
// This node is the DETERMINISTIC SAFETY NET:
//   • maps the AI's new schema -> internal fields (members->pax, month->date)
//   • field backstop (regex-catch month/pax/PHONE the AI missed) + field cache
//   • code-driven number step + Yes/No quick-assistance step (reliable, owner-kept)
//   • returning-visitor completion (destination + on-file number)
//   • serious/complaint/spam flag handling; same-reply suppression
//   • banks the profile (WhatsApp + past destinations) on qualification
// Falls back to a scripted question whenever the AI reply is empty/failed.
// ⚠️ Code node MUST return [{ json: { ... } }].
// ─────────────────────────────────────────────────────────────────────────

const up = $json || {};
let raw = '';
if (typeof up.output === 'string') raw = up.output;
else if (up.output && typeof up.output === 'object') raw = JSON.stringify(up.output);
else if (up.message && typeof up.message.content === 'string') raw = up.message.content;
else if (up.choices && up.choices[0] && up.choices[0].message) raw = up.choices[0].message.content;
else if (typeof up.text === 'string') raw = up.text;
else if (typeof up.content === 'string') raw = up.content;

let parsed = null;
try {
  let c = String(raw).replace(/```json/gi, '').replace(/```/g, '').trim();
  // The AI occasionally embeds a literal line break inside a JSON string value
  // (instead of the escaped \n) when its reply spans two lines -- that alone makes
  // the whole JSON block unparseable, silently discarding the entire turn's
  // extracted data (destination/members/month) and forcing a scripted re-ask that
  // looks exactly like the bot ignoring what was just said. Repair any literal
  // newline/carriage-return that falls INSIDE a quoted string before parsing.
  c = c.replace(/"(?:[^"\\]|\\.)*"/g, (m) => m.replace(/\r?\n/g, '\\n'));
  if (c) parsed = JSON.parse(c);
} catch (e) { parsed = null; }
if (!parsed || typeof parsed !== 'object') parsed = { reply: '', data: {}, stage: 'collecting', handoff_ready: false, flag: null };

const norm = $('Normalize input').first().json;
const knownF = norm.known_fields || {};
const visitor = norm.visitor_status || 'new';
const isReturning = visitor === 'returning';

const OB = String.fromCharCode(123) + String.fromCharCode(123);
const CB = String.fromCharCode(125) + String.fromCharCode(125);
const strip = (v) => { const t = (v === undefined || v === null) ? '' : String(v).trim(); return (t.slice(0, 2) === OB && t.slice(-2) === CB) ? '' : t; };

function cleanPhone(v) {
  if (!v) return '';
  let d = String(v).replace(/\D/g, '');
  let in10 = d;
  if (in10.length === 12 && in10.startsWith('91')) in10 = in10.slice(2);
  else if (in10.length === 11 && in10.startsWith('0')) in10 = in10.slice(1);
  if (in10.length === 10 && /^[6-9]/.test(in10)) return '+91 ' + in10.slice(0, 5) + ' ' + in10.slice(5);
  const hadPlus = String(v).trim().charAt(0) === '+';
  if (d.startsWith('00')) d = d.slice(2);
  if (hadPlus || (d.length >= 11 && d.length <= 15)) return '+' + d;
  return '';
}

// -- map AI schema -> internal (fall back to known) --
const dd = parsed.data || {};
const _rawDest = strip(dd.destination) || strip(knownF.destination);
// normalized_destination is only trustworthy from cache if the underlying destination
// hasn't changed since it was cached; otherwise it's stale from a PRIOR destination and
// must not be kept (this was silently breaking new-enquiry detection below).
const _destUnchanged = strip(knownF.destination).toLowerCase() === _rawDest.toLowerCase();
const merged = {
  destination: _rawDest,
  normalized_destination: _destUnchanged ? strip(knownF.normalized_destination) : '',
  travel_date: strip(dd.travel_month) || strip(knownF.travel_date),
  pax: strip(dd.members) || strip(knownF.pax),
  whatsapp_number: strip(knownF.whatsapp_number), // number comes from the message via backstop, not the AI
};
merged.whatsapp_number = cleanPhone(merged.whatsapp_number);
if (!merged.normalized_destination && merged.destination) merged.normalized_destination = merged.destination;

// -- NEW-ENQUIRY DETECTION (ported from the WhatsApp bot) -- a lead who already
// answered quick assistance and now names a DIFFERENT destination is starting a
// fresh enquiry (e.g. commented on another destination's post). Keep their phone;
// restart month/pax for the new trip.
const _oldDest = (strip(knownF.normalized_destination) || strip(knownF.destination)).toLowerCase();
const _newDestL = String(merged.normalized_destination || merged.destination || '').toLowerCase();
const newEnquiry = !isReturning && !!_oldDest && !!_newDestL && _newDestL !== _oldDest && !!strip(knownF.quick_assistance);
if (newEnquiry) {
  const _lfDate = strip(dd.travel_month);
  merged.travel_date = (_lfDate && _lfDate !== strip(knownF.travel_date)) ? _lfDate : '';
  const _lfPax = strip(dd.members);
  merged.pax = (_lfPax && _lfPax !== strip(knownF.pax)) ? _lfPax : '';
  const _sdNE = $getWorkflowStaticData('global');
  if (_sdNE.qaDone) delete _sdNE.qaDone[String(norm.ig_user_id)];
  if (_sdNE.awaitingQA) delete _sdNE.awaitingQA[String(norm.ig_user_id)];
  _sdNE.neSalt = _sdNE.neSalt || {};
  _sdNE.neSalt[String(norm.ig_user_id)] = Date.now();
}

// -- FIELD BACKSTOP (regex-catch what the AI missed) --
const _um = String(norm.user_message || '');
const _umL = _um.toLowerCase();
if (!merged.travel_date) {
  const _mon = _umL.match(/\b(jan(uary)?|feb(ruary)?|mar(ch)?|apr(il)?|may|jun(e)?|jul(y)?|aug(ust)?|sep(tember|t)?|oct(ober)?|nov(ember)?|dec(ember)?)\b/);
  if (_mon) merged.travel_date = _mon[0].charAt(0).toUpperCase() + _mon[0].slice(1);
  else {
    const _rel = _um.match(/next month|this month|next week|coming month|month end|year end|flexible|any ?time/i);
    if (_rel) merged.travel_date = _rel[0];
    else if (/\b(idk|i ?dont ?know|i ?don'?t ?know|not sure|dunno|no idea|unsure|whenever)\b/i.test(_umL)) merged.travel_date = 'flexible';
  }
}
if (!merged.pax) {
  const _pn = _um.match(/(\d{1,3})\s*(?:people|persons?|pax|adults?|members?|of us|travell?ers?|heads?|nos)\b/i) || _umL.match(/\bfor\s+(\d{1,3})\b/) || _umL.match(/\bwe(?:'?re| are)\s+(\d{1,3})\b/);
  if (_pn) merged.pax = _pn[1];
  else if (/\bhoneymoon\b|\bcouple\b|\bme and my (?:wife|husband|partner|hubby)\b|\bwe two\b|\bboth of us\b|\bmy spouse\b/.test(_umL)) merged.pax = '2';
  else if (/\bsolo\b|\bjust me\b|\bmyself\b|\balone\b|\bonly me\b/.test(_umL)) merged.pax = '1';
  else { const _fam = _umL.match(/family of (\d{1,2})/); if (_fam) merged.pax = _fam[1]; }
}
if (!merged.whatsapp_number) {
  const _digits = _um.replace(/[^0-9]/g, ' ');
  const _ph = _digits.match(/\b([6-9]\d{9})\b/) || _digits.match(/\b91\s*([6-9]\d{9})\b/);
  if (_ph && !/^(\d)\1{9}$/.test(_ph[1])) merged.whatsapp_number = '+91 ' + _ph[1].slice(0, 5) + ' ' + _ph[1].slice(5);
}

// -- FIELD MEMORY CACHE (bridge sheet read lag; only within a continuing chat) --
const _sdF = $getWorkflowStaticData('global');
_sdF.fieldCache = _sdF.fieldCache || {};
const _fcKey = String(norm.ig_user_id);
const _nowF = Date.now();
for (const _k in _sdF.fieldCache) { if (_nowF - ((_sdF.fieldCache[_k] || {})._ts || 0) > 48 * 3600000) delete _sdF.fieldCache[_k]; }
const _fc = _sdF.fieldCache[_fcKey] || {};
const _CF = ['destination', 'normalized_destination', 'travel_date', 'pax', 'whatsapp_number'];
if (visitor === 'continuing' && !newEnquiry) { for (const f of _CF) { if ((!merged[f] || merged[f] === '') && _fc[f]) merged[f] = _fc[f]; } }
const _fcNew = { _ts: _nowF };
for (const f of _CF) { if (merged[f] && merged[f] !== '') _fcNew[f] = merged[f]; }
_sdF.fieldCache[_fcKey] = _fcNew;

// -- completeness --
const hasDest = !!(merged.destination || merged.normalized_destination);
const hasDate = !!merged.travel_date;
const hasPax = !!merged.pax;
const hasPhone = !!merged.whatsapp_number;
const qaAnswered = !!strip(knownF.quick_assistance) && !newEnquiry;
const detailsBeforePhone = isReturning ? hasDest : (hasDest && hasDate && hasPax);
const coreReady = detailsBeforePhone && hasPhone;

const flag = (parsed.flag && ['serious', 'complaint', 'spam'].indexOf(parsed.flag) !== -1) ? parsed.flag : null;
const aiReply = strip(parsed.reply);

function scriptedNext() {
  if (!hasDest) return 'Hey, this is Rahul from Outbound Travelers! 👋😊\n\nMay I know which destination you are looking for? 🌍';
  if (!isReturning && !hasDate) return 'Great choice! Which month are you planning to travel? 🗓️';
  if (!isReturning && !hasPax) return 'And how many people are travelling? 👥';
  if (!hasPhone) return 'Perfect! 🎉\n\nJust share your WhatsApp number 📲 and our travel expert will reach out to plan everything with you 😊';
  if (!qaAnswered) return 'Thanks for your co-operation.\n\nDo you need quick assistance? Please reply Yes or No.';
  return 'Thank you! Our travel consultant will get back to you shortly. 😊';
}

// -- reply decision: code owns the transactional steps (number ask + Yes/No), AI owns the warm collection --
let replyText, askQuickAssist = false;
if (flag === 'spam') {
  replyText = '';
} else if (flag === 'serious' || flag === 'complaint') {
  replyText = aiReply || 'I completely understand — let me have our travel expert reach out and help you personally. 🙏';
} else if (detailsBeforePhone && !hasPhone) {
  const _sdP = $getWorkflowStaticData('global');
  _sdP.phoneAsk = _sdP.phoneAsk || {};
  const _nowP = Date.now();
  for (const _k in _sdP.phoneAsk) { if (_nowP - (_sdP.phoneAsk[_k].ts || 0) > 72 * 3600000) delete _sdP.phoneAsk[_k]; }
  const _pKey = String(norm.ig_user_id);
  const _pc = (_sdP.phoneAsk[_pKey] && _sdP.phoneAsk[_pKey].c) || 0;
  // Recognize an explicit refusal ("I don't have a WhatsApp number") instead of
  // telling them their non-answer "doesn't look like a valid number" -- that read as
  // broken/tone-deaf to a real customer and was a root cause of the "bot ignores me" complaint.
  const _phoneRefusal = /\b(don'?t|dont|do ?not|doesn'?t|no)\b.{0,25}\b(whatsapp|number|phone)\b/i.test(_um);
  if (_pc >= 3) {
    // Stop nagging with the same canned line after repeated failed attempts -- let the
    // AI's own natural reply through (it still won't ask for the number itself, per prompt).
    replyText = aiReply || 'No worries! Our travel expert will reach out to you here on Instagram directly. 😊';
  } else {
    _sdP.phoneAsk[_pKey] = { c: _pc + 1, ts: _nowP };
    replyText = _phoneRefusal
      ? "No worries if you don't have WhatsApp! 😊\n\nCould you share any other number, or should our expert reach you here on Instagram instead?"
      : (_pc >= 1
        ? "Hmm, that doesn't look like a valid number 😅\n\nCould you share your 10-digit WhatsApp number?"
        : 'Perfect! 🎉\n\nJust share your WhatsApp number 📲 and our travel expert will reach out to plan everything with you 😊');
  }
} else if (coreReady && !qaAnswered) {
  replyText = 'Thanks for your co-operation.\n\nDo you need quick assistance? Please reply Yes or No.';
  askQuickAssist = true;
} else {
  // The AI can self-report stage:"complete"/handoff_ready:true and write a premature
  // closing line ("our expert will reach out!") even when a required field is still
  // actually missing per our own deterministic tracking (e.g. it treats an "idk"/"not
  // sure" answer as satisfying the month without literally putting "flexible" in its
  // own data.travel_month). This is a real production bug: it skipped the mandatory
  // phone-number step entirely. Cross-check the AI's own completion claim against
  // what we actually know is filled, and never trust it over that.
  const _aiClaimsComplete = (parsed.stage === 'complete') || (parsed.handoff_ready === true);
  replyText = (_aiClaimsComplete && !detailsBeforePhone) ? scriptedNext() : (aiReply || scriptedNext());
}

// -- REPLY RECONCILIATION (ported from the WhatsApp bot) -- if the AI's reply asks
// for a field we already have (dedup/timing edge cases), replace it with the
// correct next scripted step instead of re-asking something already answered.
const _asksDest = /which (?:destination|place)|where would you|where do you|destination.*looking|looking for.*destination/i.test(replyText);
const _asksDate = /which month|what month|when (?:are|do) you|travel date|planning to travel/i.test(replyText);
const _asksPax = /how many (?:people|persons|travell?ers|of you|guests)|number of (?:people|travell?ers|pax|guests)|how many will/i.test(replyText);
const _reAsk = (_asksDest && hasDest) || (_asksDate && hasDate && !isReturning) || (_asksPax && hasPax && !isReturning);
if (_reAsk) replyText = scriptedNext();

// -- QA re-ask cap (max twice, then close) --
let qaClosed = false;
if (askQuickAssist) {
  const _sdC = $getWorkflowStaticData('global');
  _sdC.qaAsk = _sdC.qaAsk || {};
  for (const _k in _sdC.qaAsk) { if (_nowF - (_sdC.qaAsk[_k].ts || 0) > 72 * 3600000) delete _sdC.qaAsk[_k]; }
  const _cKey = String(norm.ig_user_id) + '|' + String(norm.conv_first_contact || '');
  const _c = (_sdC.qaAsk[_cKey] && _sdC.qaAsk[_cKey].c) || 0;
  if (_c >= 2) { qaClosed = true; askQuickAssist = false; replyText = 'No problem! Our travel consultant will reach out to you soon. 😊'; }
  else {
    if (_c >= 1) replyText = 'Just checking in!\n\nDo you need quick assistance? Please reply Yes or No.';
    _sdC.qaAsk[_cKey] = { c: _c + 1, ts: _nowF };
  }
}

// -- track that we asked the Yes/No question, so the next reply is recognised as a
//    button answer even if the sheet read lags behind the just-saved phone number --
_sdF.awaitingQA = _sdF.awaitingQA || {};
for (const _k in _sdF.awaitingQA) { if (_nowF - _sdF.awaitingQA[_k] > 72 * 3600000) delete _sdF.awaitingQA[_k]; }
if (askQuickAssist) _sdF.awaitingQA[_fcKey] = _nowF;
else if (strip(knownF.quick_assistance) || qaClosed) delete _sdF.awaitingQA[_fcKey];

// -- same-reply suppression: only blocks a TRUE duplicate delivery of the SAME
// incoming message (same msg_id reprocessed) -- never a different message that
// happens to produce identical canned text (e.g. repeated phone-ask retries),
// which was silently swallowing real customer replies. --
_sdF.lastReply = _sdF.lastReply || {};
for (const _k in _sdF.lastReply) { if (_nowF - (_sdF.lastReply[_k].ts || 0) > 3600000) delete _sdF.lastReply[_k]; }
const _lr = _sdF.lastReply[_fcKey];
const _rkey = String(replyText || '').trim();
const _curMsgId = String(norm.msg_id || '');
if (replyText && _lr && _lr.msgId === _curMsgId && (_nowF - _lr.ts) < 10 * 60000) replyText = '';
else if (replyText) _sdF.lastReply[_fcKey] = { text: _rkey, ts: _nowF, msgId: _curMsgId };

// -- status / notes --
const status = coreReady ? 'qualified' : ((hasDest || hasDate || hasPax || hasPhone) ? 'in_progress' : 'new');
const notes = ('Dest: ' + (merged.normalized_destination || merged.destination || '-') + ', Month: ' + (merged.travel_date || '-') + ', Pax: ' + (merged.pax || '-') + (flag ? ' [' + flag + ']' : '')).slice(0, 150);

// -- CRM push once at qualification (Button handler no longer pushes) --
const CRM_FIELDS = isReturning ? ['destination', 'whatsapp_number'] : ['destination', 'travel_date', 'pax', 'whatsapp_number'];
const crmReady = CRM_FIELDS.every((f) => merged[f] && merged[f] !== '');
const crmWasReady = CRM_FIELDS.every((f) => strip(knownF[f]) !== '');
const crmPush = crmReady && (!crmWasReady || newEnquiry);

// -- bank the profile (survives the 48h reset) --
if (hasPhone && hasDest) {
  _sdF.profiles = _sdF.profiles || {};
  const _pv = _sdF.profiles[_fcKey] || { whatsapp: '', past: [] };
  _pv.whatsapp = merged.whatsapp_number || _pv.whatsapp;
  const _dn = merged.normalized_destination || merged.destination;
  _pv.past = _pv.past || [];
  if (_dn && _pv.past.indexOf(_dn) === -1) _pv.past.push(_dn);
  if (_pv.past.length > 8) _pv.past = _pv.past.slice(-8);
  _pv.ts = _nowF;
  _sdF.profiles[_fcKey] = _pv;
}

// -- timestamps --
const nowIST = new Date(_nowF + 5.5 * 3600000).toISOString().replace('T', ' ').slice(0, 19);
const firstContact = (norm.conv_first_contact && String(norm.conv_first_contact).trim()) || (norm.existing_first_contact_ts && String(norm.existing_first_contact_ts).trim()) || nowIST;

return [{
  json: {
    ig_user_id:           norm.ig_user_id,
    ig_username:          norm.ig_username,
    full_name:            strip(norm.ig_fullname),
    reply:                replyText,
    intent:               'travel_lead',
    is_lead:              hasPhone,
    destination:          merged.destination,
    normalized_destination: merged.normalized_destination,
    travel_date:          merged.travel_date,
    pax:                  merged.pax,
    whatsapp_number:      merged.whatsapp_number,
    quick_assistance:     qaClosed ? 'no_response' : (newEnquiry ? '' : strip(knownF.quick_assistance)),
    ask_quick_assistance: askQuickAssist,
    notes:                notes,
    status:               status,
    crm_push:             crmPush,
    flag:                 flag,
    visitor_status:       visitor,
    first_contact_ts:     firstContact,
    last_update_ts:       nowIST,
  },
}];

